const checkpoints = [];

const parseJson = (key, fallback) => {
  try {
    const raw = localStorage.getItem(key);
    if (raw === null || raw === undefined) return fallback;
    const v = JSON.parse(raw);
    return (v === null || v === undefined) ? fallback : v;
  } catch (e) {
    return fallback;
  }
};

const timeToMinutes = (t) => {
  if (!t) return null;
  const parts = t.split(':');
  if (parts.length < 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
};

// Instrumentation: did user view checkout for this task?
let task1CheckoutViewedRaw = localStorage.getItem('task1_checkoutViewed');
let task1CheckoutViewed;
try {
  task1CheckoutViewed = JSON.parse(task1CheckoutViewedRaw);
} catch (e) {
  task1CheckoutViewed = (task1CheckoutViewedRaw === 'true');
}

let cart = parseJson('cart', null);
if (Array.isArray(cart)) {
  cart = cart[0] || null;
}
const cartItemsAll = parseJson('cart_items', []);
const cartItems = cart && cart.id ? cartItemsAll.filter(ci => ci.cart_id === cart.id) : [];
const attractions = parseJson('attractions', []);
const timeslots = parseJson('attraction_timeslots', []);
const promoCodes = parseJson('promo_codes', []);

// Find a high-scare maze that is not kid-friendly
const mazeAttractions = attractions.filter(a => a && a.attraction_type === 'maze' && typeof a.scare_level === 'number' && a.scare_level >= 4 && !a.is_kid_friendly);
const targetMaze = mazeAttractions[0] || null;

const targetDate = '2025-10-29';
let cheapestSlot = null;
if (targetMaze) {
  const qualifyingSlots = timeslots.filter(ts => {
    if (!ts || ts.attraction_id !== targetMaze.id || ts.status !== 'available' || !ts.start_datetime) return false;
    const d = ts.start_datetime.slice(0, 10);
    if (d !== targetDate) return false;
    const t = ts.start_datetime.slice(11, 16);
    const mins = timeToMinutes(t);
    return mins !== null && mins >= 18 * 60; // after 6:00 PM
  });
  qualifyingSlots.forEach(ts => {
    if (!cheapestSlot || (typeof ts.standard_price === 'number' && ts.standard_price < cheapestSlot.standard_price)) {
      cheapestSlot = ts;
    }
  });
}

let totalTicketsCheapest = 0;
let hasValidPromoOnCheapest = false;
if (targetMaze && cheapestSlot) {
  const ticketsForSlot = cartItems.filter(ci => ci.item_type === 'ticket' && ci.ticket_attraction_id === targetMaze.id && ci.ticket_timeslot_id === cheapestSlot.id);
  totalTicketsCheapest = ticketsForSlot.reduce((sum, ci) => sum + (typeof ci.quantity === 'number' ? ci.quantity : 0), 0);

  hasValidPromoOnCheapest = ticketsForSlot.some(ci => {
    if (!ci.promo_code_id) return false;
    const promo = promoCodes.find(p => p.id === ci.promo_code_id);
    if (!promo || !promo.is_active) return false;
    if (promo.applies_to !== 'tickets_only' && promo.applies_to !== 'all_items') return false;
    // Date validity check (best-effort; if parsing fails, we ignore date bounds)
    const now = new Date();
    if (promo.valid_from) {
      const from = new Date(promo.valid_from);
      if (!isNaN(from.getTime()) && now < from) return false;
    }
    if (promo.valid_to) {
      const to = new Date(promo.valid_to);
      if (!isNaN(to.getTime()) && now > to) return false;
    }
    if (typeof promo.min_order_total === 'number') {
      // Approximate: require the line_total to meet min_order_total
      const lineTotal = typeof ci.line_total === 'number' ? ci.line_total : 0;
      if (lineTotal < promo.min_order_total) return false;
    }
    return true;
  });
}

const hasQualifyingTickets = !!(targetMaze && cheapestSlot && totalTicketsCheapest >= 4);
const viewedCheckoutWithQualifying = !!(hasQualifyingTickets && task1CheckoutViewed === true);

// CP1 (0.4): User has 4+ tickets for a high-scare, non–kid-friendly maze on Oct 29 using the cheapest timeslot after 6 PM
checkpoints.push({ passed: hasQualifyingTickets, weight: 0.4 });

// CP2 (0.3): Those tickets have a valid promo code applied that can apply to tickets
checkpoints.push({ passed: hasQualifyingTickets && hasValidPromoOnCheapest, weight: 0.3 });

// CP3 (0.3): User viewed checkout after having qualifying tickets in cart
checkpoints.push({ passed: viewedCheckoutWithQualifying, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

