  const tags = Array.isArray(ev.tags) ? ev.tags.map(t => String(t).toLowerCase()) : [];
  const hasZombie = tags.some(t => t.indexOf('zombie') !== -1);
  const hasMakeup = tags.some(t => t.indexOf('makeup') !== -1);
  if (!hasZombie || !hasMakeup) return false;
  const d = ev.start_datetime.slice(0, 10);
  if (d < '2025-10-28' || d > '2025-10-30') return false;
  const t = ev.start_datetime.slice(11, 16);
  const mins = timeToMinutes(t);
  if (mins === null) return false;
  // between 1:00 PM and 4:00 PM (16:00) inclusive
  return mins >= 13 * 60 && mins <= 16 * 60;
});

// Find earliest such event by start_datetime
let earliestEvent = null;
candidateEvents.forEach(ev => {
  if (!earliestEvent) {
    earliestEvent = ev;
  } else if (ev.start_datetime < earliestEvent.start_datetime) {
    earliestEvent = ev;
  }
});

let hasRegForEarliestParty3 = false;
let hasRegWithCorrectDetails = false;

if (earliestEvent) {
  regs.forEach(reg => {
    if (!reg || reg.event_id !== earliestEvent.id) return;
    if (reg.party_size !== 3) return;
    hasRegForEarliestParty3 = true;
    const nameOk = reg.full_name === 'Alex Carter';
    const emailOk = reg.email === 'alex@example.com';
    const phoneOk = reg.phone === '555-0123';
    const newsletterOk = reg.newsletter_opt_in === false;
    if (nameOk && emailOk && phoneOk && newsletterOk) {
      hasRegWithCorrectDetails = true;
    }
  });
}

// CP1 (0.7): Registration exists for a party of 3 on the earliest qualifying workshop
checkpoints.push({ passed: !!(earliestEvent && hasRegForEarliestParty3), weight: 0.7 });

// CP2 (0.3): That registration uses the expected contact details and newsletter preference
checkpoints.push({ passed: hasRegWithCorrectDetails, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
